    public static void ApplyAllAnimeStats(this Pets pet, AnimeStats animeStats)
    {
        if (animeStats == null) return;
        pet.Health = pet.Health + animeStats.Health + pet.BaseStats.Health * animeStats.PercentAllHealth / 100;
        pet.PhysicalAttack = pet.PhysicalAttack + animeStats.PhysicalAttack + pet.BaseStats.PhysicalAttack * animeStats.PercentAllPhysicalAttack / 100;
        pet.PhysicalDefense = pet.PhysicalDefense + animeStats.PhysicalDefense + pet.BaseStats.PhysicalDefense * animeStats.PercentAllPhysicalDefense / 100;
        pet.MagicalAttack = pet.MagicalAttack + animeStats.MagicalAttack + pet.BaseStats.MagicalAttack * animeStats.PercentAllMagicalAttack / 100;
